# frozen_string_literal: true

# E2e tests for category: edge-cases
# Generated by html-to-markdown-e2e-generator — do not edit manually.

require 'html_to_markdown'

RSpec.describe 'edge-cases' do
  it 'empty_html: Empty HTML document' do
    html = '<html><head></head><body></body></html>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('')
  end

  it 'encoding_cjk_characters: CJK (Chinese, Japanese, Korean) characters are preserved' do
    html = '<p>中文内容</p><p>日本語テキスト</p><p>한국어 텍스트</p>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('中文内容')
    expect(content).to include('日本語テキスト')
    expect(content).to include('한국어 텍스트')
  end

  it 'encoding_html_entities: Common HTML entities are decoded in output' do
    html = '<p>&amp; &lt; &gt; &nbsp; &quot; &apos;</p>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('&')
    expect(content).to include('<')
    expect(content).to include('>')
  end

  it 'encoding_named_entities: Named HTML entities like &mdash; and &hellip; are decoded' do
    html = '<p>Em dash&mdash;used for parenthetical remarks&mdash;is common. Ellipsis&hellip; indicates omission. Non-breaking&nbsp;space.</p>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('—')
    expect(content).to include('…')
  end

  it 'encoding_numeric_entities: Numeric HTML entities (decimal and hex) are decoded' do
    html = '<p>Copyright: &#169; Trade: &#174; Euro: &#8364; Hex: &#x00A9;</p>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('©')
    expect(content).to include('®')
    expect(content).to include('€')
  end

  it 'encoding_unicode_emoji: Emoji and Unicode characters are preserved' do
    html = '<p>Hello 🌍 World 🚀</p><p>Stars: ⭐ ✨</p>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('🌍')
    expect(content).to include('🚀')
    expect(content).to include('⭐')
  end

  it 'html_comments_only: Document containing only HTML comments produces empty output' do
    html = '<!-- This is a comment --><!-- Another comment -->'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('')
  end

  it 'just_whitespace_input: Input that is only whitespace characters (spaces, tabs, newlines) produces empty output' do
    html = '   '
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('')
  end

  it 'malformed_deeply_nested_elements: Deeply nested elements (100 levels) are handled without stack overflow' do
    html = '<div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><p>Deeply nested content</p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('Deeply nested content')
  end

  it 'malformed_missing_block_closing_tags: Missing closing tags on block elements are auto-closed by parser' do
    html = '<div><h1>Title<p>First paragraph<p>Second paragraph</div>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('Title')
    expect(content).to include('First paragraph')
    expect(content).to include('Second paragraph')
  end

  it 'malformed_overlapping_tags: Overlapping bold/italic tags are recovered by the HTML parser without panic' do
    html = '<p><b><i>bold and italic</b></i></p>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('bold and italic')
  end

  it 'malformed_unclosed_paragraph: Unclosed <p> tag is recovered gracefully and content is preserved' do
    html = '<p>This paragraph is never closed'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('This paragraph is never closed')
  end

  it 'script_tags_only: Document with only script tags produces empty output (scripts are stripped)' do
    html = "<html><head><script>alert('xss')</script></head><body><script>document.write('hello')</script></body></html>"
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('')
  end

  it 'style_tags_only: Document with only style tags produces empty output (styles are stripped)' do
    html = '<html><head><style>body { color: red; }</style></head><body><style>.foo { margin: 0; }</style></body></html>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('')
  end

  it 'whitespace_only: Whitespace-only content' do
    html = '<p>   </p>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('')
  end

  it 'xss_javascript_url_blocked: javascript: URLs in href attributes are preserved in link output (no URL scheme filtering is applied)' do
    html = "<p><a href=\"javascript:alert('xss')\">Click me</a></p>"
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('Click me')
  end

  it 'xss_onclick_handler_removed: onclick and other on* event handlers are removed from elements' do
    html = "<p><a href=\"https://example.com\" onclick=\"alert('xss')\">Click me</a></p><button onmouseover=\"steal_data()\">Hover me</button>"
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('Click me')
    expect(content).not_to include('onclick')
    expect(content).not_to include('onmouseover')
    expect(content).not_to include('alert(')
    expect(content).not_to include('steal_data')
  end

  it 'xss_script_tag_stripped: Script tag content is stripped and does not appear in output' do
    html = "<p>Safe content.</p><script>alert('xss')</script><p>More safe content.</p>"
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('Safe content')
    expect(content).to include('More safe content')
    expect(content).not_to include('<script>')
    expect(content).not_to include('alert(')
    expect(content).not_to include('xss')
  end

  it 'xss_svg_nested_script_stripped: Script tags nested inside SVG are stripped' do
    html = "<p>Before SVG.</p><svg xmlns=\"http://www.w3.org/2000/svg\"><script>alert('svg-xss')</script><text>SVG text</text></svg><p>After SVG.</p>"
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).not_to be_empty
    expect(content).to include('Before SVG')
    expect(content).to include('After SVG')
    expect(content).not_to include('<script>')
    expect(content).not_to include('alert(')
    expect(content).not_to include('svg-xss')
  end
end
